func topKFrequentElements(data []int) *list.List {
    frequencyMap := make(map[int]int)
    for _, num := range data {
        frequencyMap[num]++
    }

    type freqPair struct {
        num  int
        freq int
    }

    freqPairs := make([]freqPair, 0, len(frequencyMap))
    for num, freq := range frequencyMap {
        freqPairs = append(freqPairs, freqPair{num, freq})
    }

    sort.Slice(freqPairs, func(i, j int) bool {
        return freqPairs[i].freq > freqPairs[j].freq
    })

    k := 2 // Change this value to get top k elements
    result := list.New()
    for i := 0; i < k && i < len(freqPairs); i++ {
        result.PushBack(freqPairs[i].num)
    }

    return result
}

