package main

import (
    "container/heap"
    "fmt"
)

type Item struct {
    value    int
    frequency int
}

type MinHeap []Item

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i].frequency < h[j].frequency }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MinHeap) Push(x interface{}) {
    *h = append(*h, x.(Item))
}

func (h *MinHeap) Pop() interface{} {
    old := *h
    n := len(old)
    item := old[n-1]
    *h = old[0 : n-1]
    return item
}

func topKFrequentElements(data []int) []int {
    frequencyMap := make(map[int]int)
    for _, num := range data {
        frequencyMap[num]++
    }

    k := 2 // Example value for k, you can change it as needed
    minHeap := &MinHeap{}

    for value, freq := range frequencyMap {
        heap.Push(minHeap, Item{value: value, frequency: freq})
        if minHeap.Len() > k {
            heap.Pop(minHeap)
        }
    }

    result := make([]int, minHeap.Len())
    for i := minHeap.Len() - 1; i >= 0; i-- {
        item := heap.Pop(minHeap).(Item)
        result[i] = item.value
    }

    return result
}

